final:
module full_adder(
    input wire a,
    input wire b,
    input wire cin,
    output wire sum,
    output wire cout
    );

wire unused_axorb;
wire aandb;
wire axorb_and_cin;

xor (unused_axorb, a, b);
xor (sum, unused_axorb, cin);
and (aandb, a, b);
and (axorb_and_cin, unused_axorb, cin);
or (cout, aandb, axorb_and_cin);

endmodule
